'use strict';

const express = require('express');

function getSecurityHeaders() {
  const headers = {
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Referrer-Policy': 'no-referrer',
    'X-XSS-Protection': '0',
  };

  if (process && process.env && process.env.FORTRESS_HSTS === 'true') {
    headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains';
  }

  return headers;
}

function applyHeaders(setHeader) {
  const headers = getSecurityHeaders();
  Object.keys(headers).forEach((key) => {
    setHeader(key, headers[key]);
  });
}

function expressMiddleware(req, res, next) {
  applyHeaders((k, v) => res.setHeader(k, v));
  next();
}

async function koaMiddleware(ctx, next) {
  applyHeaders((k, v) => ctx.set(k, v));
  await next();
}

const router = express.Router();
router.use(expressMiddleware);
router.get('/status/fo', (req, res) => {
  res.json({ status: 'ok', fortress: true });
});

module.exports = {
  expressMiddleware,
  koaMiddleware,
  router,
};

